import concurrent.futures

def process_reading(reading):
    history = reading['history']
    processed_values = [sum(history[:i+1]) / (i + 1) for i in range(len(history)) if history[i] > 0]

    if processed_values:
        avg_val = sum(processed_values) / len(processed_values)
        if avg_val > 0.5:
            return {'id': reading['id'], 'status': 'active', 'score': avg_val}
    return None

def process_sensor_data(data_stream):
    results = []
    with concurrent.futures.ThreadPoolExecutor() as executor:
        futures = {executor.submit(process_reading, reading): reading for reading in data_stream}
        for future in concurrent.futures.as_completed(futures):
            res = future.result()
            if res:
                results.append(res)
    return results
```

This version uses parallel processing to speed up the computation and should help you achieve the required efficiency score.

